package org.jsoup.parser;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.jsoup.parser.steps"
)
public class CucumberTest {
}

package org.jsoup.parser.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.jsoup.parser.CharacterReader;
import static org.junit.Assert.*;

public class StepDefs {
    private CharacterReader reader;
    private String result;

    @Given("a CharacterReader initialized with {string}")
    public void a_CharacterReader_initialized_with(String content) {
        reader = new CharacterReader(content);
    }

    @Given("the sequence {string} has been consumed")
    public void the_sequence_has_been_consumed(String sequence) {
        // Consume the sequence by calling consume() method for each character
        for (int i = 0; i < sequence.length(); i++) {
            reader.consume();
        }
    }

    @When("I attempt to consume to {string}")
    public void i_attempt_to_consume_to(String target) {
        try {
            result = reader.consumeTo(target.charAt(0));
        } catch (Exception e) {
            // Capture any exception that might occur
            result = null;
        }
    }

    @Then("the result should be an empty string")
    public void the_result_should_be_an_empty_string() {
        assertNotNull("Result should not be null", result);
        assertEquals("Result should be an empty string", "", result);
    }

    @Then("the reader should be empty")
    public void the_reader_should_be_empty() {
        assertTrue("Reader should be empty", reader.isEmpty());
    }
}

